  actual_output     NUMERIC(12,2) NOT NULL DEFAULT 0,
  output_unit       TEXT NOT NULL DEFAULT 'kg',
  reject_qty        NUMERIC(12,2) NOT NULL DEFAULT 0,

  -- Downtime
