  downtime_reason   TEXT,

  -- Utility readings
  power_kwh         NUMERIC(10,2),
  water_kl          NUMERIC(10,3),

  -- QC
  qc_checks_done    INT NOT NULL DEFAULT 0,
  qc_issues         TEXT,

  -- Observations / Safety
  observations      TEXT,
  safety_incidents  INT NOT NULL DEFAULT 0,

  created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- RLS
