-- 1. Modify documents table to support versioning and approvals
ALTER TABLE documents
ADD COLUMN IF NOT EXISTS version INTEGER DEFAULT 1,
ADD COLUMN IF NOT EXISTS parent_id TEXT REFERENCES documents(id),
ADD COLUMN IF NOT EXISTS approved_by UUID REFERENCES auth.users(id),
ADD COLUMN IF NOT EXISTS approved_at TIMESTAMPTZ;

-- Drop constraints if needed for status, but it's typically just text in Supabase
-- Statuses now include: 'draft', 'pending_approval', 'approved', 'issued', 'rejected', 'cancelled', 'archived'

-- 2. Create dms_links table for connecting documents to modules
CREATE TABLE IF NOT EXISTS dms_links (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  document_id TEXT REFERENCES documents(id) ON DELETE CASCADE,
  entity_type TEXT NOT NULL, -- e.g., 'batch', 'employee', 'recipe'
  entity_id TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_dms_links_doc ON dms_links(document_id);
CREATE INDEX IF NOT EXISTS idx_dms_links_entity ON dms_links(entity_type, entity_id);

ALTER TABLE dms_links ENABLE ROW LEVEL SECURITY;
CREATE POLICY "allow_all_dms_links" ON dms_links FOR ALL USING (true) WITH CHECK (true);

-- 3. Create dms_access_logs table
CREATE TABLE IF NOT EXISTS dms_access_logs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  document_id TEXT REFERENCES documents(id) ON DELETE CASCADE,
  user_id TEXT, -- nullable for public QR accesses
  action TEXT NOT NULL, -- e.g., 'viewed', 'printed', 'downloaded', 'verified'
  ip_address TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_dms_access_logs_doc ON dms_access_logs(document_id);

ALTER TABLE dms_access_logs ENABLE ROW LEVEL SECURITY;
CREATE POLICY "allow_all_dms_access" ON dms_access_logs FOR ALL USING (true) WITH CHECK (true);


-- ============================================================
-- INJECTED FILE: inventory_upgrade.sql
-- ============================================================

-- ============================================================
-- Phase 7 Inventory & Material Control Upgrade
-- ============================================================

-- 1. Add erp_product_id to GRNs and Lots to link strictly to Material Master
ALTER TABLE public.grns
ADD COLUMN IF NOT EXISTS erp_product_id UUID REFERENCES public.products(id) ON DELETE SET NULL;

ALTER TABLE public.lots
ADD COLUMN IF NOT EXISTS erp_product_id UUID REFERENCES public.products(id) ON DELETE SET NULL;

-- 2. Create Stock Ledger Table
CREATE TABLE IF NOT EXISTS public.stock_ledger (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    lot_id TEXT REFERENCES public.lots(id) ON DELETE CASCADE,
    fg_lot_id TEXT REFERENCES public.fg_lots(id) ON DELETE CASCADE,
    erp_product_id UUID REFERENCES public.products(id) ON DELETE SET NULL,
    transaction_type TEXT NOT NULL CHECK (transaction_type IN ('IN', 'OUT', 'ADJUSTMENT', 'TRANSFER')),
    qty_change NUMERIC(12,3) NOT NULL, -- positive for IN, negative for OUT
    reference_id TEXT, -- e.g. dispatch_id, invoice_id, or production_run_id
    notes TEXT,
    created_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,
    created_at TIMESTAMPTZ DEFAULT now()
);

-- 3. Create Trigger to Auto-Update Lots/FgLots Remaining Qty based on Ledger inserts
CREATE OR REPLACE FUNCTION update_lot_remaining_qty()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.lot_id IS NOT NULL THEN
        UPDATE public.lots
        SET remaining_qty = remaining_qty + NEW.qty_change
        WHERE id = NEW.lot_id;
    END IF;
    IF NEW.fg_lot_id IS NOT NULL THEN
        UPDATE public.fg_lots
        SET available_qty = available_qty + NEW.qty_change
        WHERE id = NEW.fg_lot_id;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trigger_update_lot_qty ON public.stock_ledger;

CREATE TRIGGER trigger_update_lot_qty
AFTER INSERT ON public.stock_ledger
FOR EACH ROW
EXECUTE FUNCTION update_lot_remaining_qty();


